import android.content.Context;
import android.os.Build;
import android.util.Log;
import android.widget.Toast;

public class BankingModule {
    private double accountBalance;
    private Context context;

    public BankingModule(Context context, double initialBalance) {
        this.context = context;
        this.accountBalance = initialBalance;
    }

    public double getAccountBalance() {
        return accountBalance;
    }

    public boolean processTransaction(double amount) {
        if (isDeviceSecure() && amount > 0) {
            accountBalance -= amount;
            Toast.makeText(context, "Transaction successful. New balance: " + accountBalance, Toast.LENGTH_SHORT).show();
            return true;
        } else {
            Toast.makeText(context, "Transaction failed. Device integrity check failed or invalid amount.", Toast.LENGTH_SHORT).show();
            return false;
        }
    }

    private boolean isDeviceSecure() {
        return checkDeviceIntegrity() && checkForRootAccess();
    }

    private boolean checkDeviceIntegrity() {
        // Simple check for device model and manufacturer
        String manufacturer = Build.MANUFACTURER;
        String model = Build.MODEL;
        Log.d("DeviceIntegrity", "Manufacturer: " + manufacturer + ", Model: " + model);
        return !model.contains("Emulator") && !manufacturer.equals("unknown");
    }

    private boolean checkForRootAccess() {
        // Basic check for root access
        String[] paths = {"/system/app/Superuser.apk", "/sbin/su", "/system/bin/su", "/system/xbin/su"};
        for (String path : paths) {
            if (new java.io.File(path).exists()) {
                return false;
            }
        }
        return true;
    }
}